// ─── Types ────────────────────────────────────────────────────────────────────

enum CalloutType { tip, warning, info, phLaw }

class GuideSection {
  final String heading;
  final String content;
  final List<String> items;
  final CalloutType? calloutType;
  final String? calloutText;

  const GuideSection({
    required this.heading,
    required this.content,
    this.items = const [],
    this.calloutType,
    this.calloutText,
  });
}

class ToolLink {
  final String href;
  final String label;
  const ToolLink({required this.href, required this.label});
}

class Guide {
  final String slug;
  final String title;
  final String description;
  final String category;
  final int readMinutes;
  final List<ToolLink> toolLinks;
  final List<GuideSection> sections;

  const Guide({
    required this.slug,
    required this.title,
    required this.description,
    required this.category,
    required this.readMinutes,
    this.toolLinks = const [],
    required this.sections,
  });
}

class ChecklistReference {
  final String label;
  final String url;
  const ChecklistReference({required this.label, required this.url});
}

class ChecklistItem {
  final String id;
  final String title;
  final String description;
  final String why;
  final String how;
  final String priority; // 'critical', 'important', 'good-to-have'
  final String? appLink;
  final String? appLinkLabel;
  final List<String> requirements;
  final List<String> steps;
  final String? fees;
  final String? processingTime;
  final List<String> tips;
  final List<ChecklistReference> references;

  const ChecklistItem({
    required this.id,
    required this.title,
    required this.description,
    this.why = '',
    this.how = '',
    this.priority = 'important',
    this.appLink,
    this.appLinkLabel,
    this.requirements = const [],
    this.steps = const [],
    this.fees,
    this.processingTime,
    this.tips = const [],
    this.references = const [],
  });
}

class LifeStage {
  final String slug;
  final String title;
  final String subtitle;
  final String ageRange;
  final String description;
  final Color color;
  final IconData icon;
  final String coverImage;
  final List<Guide> guides;
  final List<String> checklistItemIds;

  const LifeStage({
    required this.slug,
    required this.title,
    required this.subtitle,
    required this.ageRange,
    required this.description,
    required this.color,
    required this.icon,
    required this.coverImage,
    required this.guides,
    this.checklistItemIds = const [],
  });

  List<ChecklistItem> get checklist =>
      checklistItemIds
          .where((id) => kChecklistItems.containsKey(id))
          .map((id) => kChecklistItems[id]!)
          .toList();
}

